import type { IntentProps } from '../../../core/slots/Intent/Intent.js';
import type { BehaviorTrackingProps } from '../../../core/types/behavior-tracking-props.js';

/**
 * @public
 */
export type ToolbarPlacement =
  | 'top-right'
  | 'top-left'
  | 'bottom-right'
  | 'bottom-left';

/**
 * Props for the ChartToolbar component
 * @public
 */
export interface ChartToolbarProps {
  /** Initial placement for the toolbar
   * @defaultValue 'top-right'
   */
  placement?: ToolbarPlacement;
}

/**
 * Internal toolbar configuration interface
 * @internal
 */
export interface InternalChartToolbarConfig extends ChartToolbarProps {
  /** When enabled show the toolbar in collapsed state */
  collapsed?: boolean;
  /** When enabled the toolbar can be dragged inside the container */
  draggable?: boolean;
  /** Initial placement for the toolbar */
  placement: ToolbarPlacement;
}

/**
 * Internal configuration - when the config is already in place after iterate slots
 * and the same needed for the context
 * Note: Do not make this one public.
 * @internal
 */
export interface InternalChartToolbarConfigured
  extends Omit<InternalChartToolbarConfig, 'placement'>,
    BehaviorTrackingProps {
  downloadData?: { enabled: boolean };
  intents?: Array<IntentProps>;
  placement?: ToolbarPlacement;
}

// Public interface, is related to InternalChartToolbarConfig
/**
 * Properties configurable by Configuration Provider
 * @public
 */
export interface ChartToolbarConfig extends ChartToolbarProps {
  /**
   * When enabled show the download data button in the toolbar
   * @deprecated - Will be removed in next breaking version. Use DownloadCSV slot instead.
   */
  downloadData?: { enabled: boolean };
  /** When enabled show the toolbar in collapsed state */
  collapsed?: boolean;
  /**
   *  When enabled the toolbar can be dragged inside the container
   *  @deprecated - Will be removed in next breaking version. Toolbar is always draggable.
   */
  draggable?: boolean;
  /**
   * When enabled show the intent button in the toolbar
   * @deprecated - Will be removed in next breaking version. Use Intent slot instead.
   */
  intents?: Array<IntentProps>;
}

/** @internal */
export type A11yToolbarTabIndex = Record<string, number>;

/** Base Props for the ChartToolbar implementation
 * @public
 */
export interface BaseToolbarProps
  extends ChartToolbarProps,
    BehaviorTrackingProps {
  /** Decides if the toolbar is visible or hidden
   * @defaultValue false
   */
  hidden?: boolean;
}

/** Props for the ChartToolbar implementation when it could be draggable
 * @public
 */
export interface DraggableToolbarProps extends BaseToolbarProps {
  /** Decides if the toolbar is draggable
   * @deprecated - This key will be removed in a future release
   * @defaultValue false
   */
  draggable?: boolean;
}

export const defaultToolbarConfig: InternalChartToolbarConfig = {
  placement: 'top-right',
};
